var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"치후유가 파티룸을 선택할 줄은 몰랐어.","JPN":"まさか千冬がパーティールームを選ぶなんてね。","ENG":"I did not expect you to choose the rental recreation room.","TWN":"千冬竟然會選擇派對包廂。"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"후후. 여유를 가지는 것이 좋다고 생각한 것뿐입니다.","JPN":"ふふ。のんびりできる方が良いと思っただけです。","ENG":"Haha. I just thought it would be good for us to take a little break.","TWN":"呵呵，只是覺得需要放鬆一下而已。"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"게다가 시끄러운 것보단 둘이서 불꽃놀이를 감상하는 것도 좋다고 생각했거든요.","JPN":"それに、騒がしいのよりも、二人で静かに花火を鑑賞できる方が良いと思いました。","ENG":"I also thought it would be better for us to watch the fireworks in peace, rather than in a crowd.","TWN":"而且與其吵吵鬧鬧，我更喜歡二個人一起看煙火。"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"어쩌면 드레스를 입으니 들뜬 걸지도 모르겠습니다.","JPN":"もしかすると、ドレスを着て心が浮かれていたのかもしれません。","ENG":"Perhaps I am overly thrilled from wearing this dress.","TWN":"或許是因為穿上這件禮服讓我有點興奮吧。"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"나는 기쁘기만 한걸.","JPN":"私は嬉しかったわ。","ENG":"I am glad, though.","TWN":"我覺得很開心。"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"치후유가 조금 더 표현을 해줬으면 했거든.","JPN":"千冬にもっと色々表現してほしかったから。","ENG":"I wish you would express yourself more.","TWN":"我一直希望千冬能多表達一些情感，"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"우리 나이 또래들처럼 말이야.","JPN":"年相応にね。","ENG":"Like the other girls of our age.","TWN":"像我們這個年紀的孩子一樣。"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"언니……","JPN":"姉さん……","ENG":"Sis...","TWN":"姊姊……"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"오붓하게 둘이 있게 됐네? 뭐라도 좀 먹을까?","JPN":"こぢんまりと二人きりになったわね。何か食べようか？","ENG":"I guess it is just us two now. Would you like to eat something?","TWN":"難得只有我們二個，要去吃點什麼嗎？"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"가능하다면 빙수를 먹을 수 있을까요?","JPN":"できれば、かき氷を食べてもいいでしょうか。","ENG":"Would it be possible to eat shaved ice?","TWN":"可以的話，我想吃刨冰。"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"빙수? 안되는 건 아니지만, 이유가 궁금한데?","JPN":"かき氷？　ダメってわけではないけど、理由が気になるわ。","ENG":"Shaved ice? It is not impossible, but why?","TWN":"刨冰？不是不行，只是好奇為什麼？"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"그건……","JPN":"それは……","ENG":"That is...","TWN":"因為……"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"어렸을 적의 추억이…… 떠올랐기 때문입니다.","JPN":"小さい頃の思い出が……思い浮かんだからです。","ENG":"That is because... I was reminded of a childhood memory.","TWN":"這會讓我想起小時候……"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"어렸을 적…… 추억?","JPN":"小さい頃の……思い出？","ENG":"Childhood... memory?","TWN":"想起……小時候？"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"네. 언니께서 힘들 때마다 수련중인 저를 찾아오신 걸 기억하시는지요?","JPN":"はい。姉さんが辛い時、修練中の私を訪ねてきたことを覚えていますか？","ENG":"Yes. Do you remember when you would visit me every time you were stressed?","TWN":"是的。姊姊還記得，每次你遇到困難時，你都會來我修練的地方找我嗎？"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"응. 길을 잃고 헤매느니, 치후유를 찾아오라고 했지.","JPN":"うん。道に迷うくらいなら自分を訪ねるように言われて。","ENG":"Yes. You said I should come to you instead of wandering around and getting lost.","TWN":"記得。你說過，遇到困難就去找你。"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"어른들이 찾지 못하는 수련 장소들이 많다고 말이야.","JPN":"大人も探せないような修練場が多いんだって。","ENG":"You said you knew a lot of training grounds that the adults did not know about.","TWN":"而且很多修練的地方大人們都找不到。"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"네. 꽤 재밌게 놀았었죠.","JPN":"はい。大変楽しく遊びました。","ENG":"Yes. We had quite some fun.","TWN":"沒錯，所以我們玩得很開心。"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"마음 놓고 누워 있기도 했고, 어른들 눈치 안 보고 크게 웃기도 했지.","JPN":"何の心配もなく寝転んだり、大人の目を気にせず大笑いもしたわね。","ENG":"We would lie down and relax, or laugh out loud without worrying about the adults.","TWN":"躺著休息，不用顧忌大人的眼神，開懷大笑。"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"서로 합을 주고받다가 머리에 큰 혹이 났던 일도 기억나는군요.","JPN":"一緒に修練して、頭に大きなこぶができたことも覚えています。","ENG":"I remember how I got a big bump on my head after training with you.","TWN":"還記得我們切磋時，不小心在頭上打出一個包。"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"그, 그땐……! 치후유가 내 몸에 상처를 낼 수 없다면서 갑자기 검을 내렸잖아.","JPN":"あ、あの時は……！　千冬が私を傷つけることができないからっていきなり刀を下ろすから。","ENG":"Th-that's...! You lowered your sword saying how you could not make a scratch on my body.","TWN":"那，那時候……！千冬說不想傷到我，突然就收起劍。"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"언니가 얼마나 놀랐는지 알아?","JPN":"私がどれだけ驚いたかわかる？","ENG":"Do you know how shocked I was?","TWN":"姊姊當時多驚訝你知道嗎？"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"그때 눈물을 참느라 혼났습니다.","JPN":"あの時、涙をこらえるのに必死でした。","ENG":"It was difficult to hold my tears in.","TWN":"我那時候忍眼淚忍得很辛苦呢。"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"그건 미안하게 생각해……","JPN":"それは悪かったわね……","ENG":"I am sorry about that...","TWN":"那件事我一直感到很抱歉……"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"몰래 도시로 나갔던 것도 기억나는군요.","JPN":"こっそり街まで出たこともありましたね。","ENG":"I also remember sneaking out to the city.","TWN":"還記得我們偷偷溜到城裡去的事。"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"그렇게 몰래 나가서 사 먹었던 빙수, 생각나십니까?","JPN":"そこで食べたかき氷のこと、覚えていますか？","ENG":"Do you remember the shaved ice we had after we snuck out?","TWN":"那次偷偷溜出去吃的刨冰，你還記得嗎？"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"아~ 내가 치후유 손을 잡고 강제로 끌고 간 날 말하는 거구나?","JPN":"あ～私が千冬の手を引いて無理やり出た日のことね。","ENG":"Oh! You mean when I took your hand and dragged you out?","TWN":"喔～你是說我硬拉著你的手去的那次嗎？"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"저는 언니를 지켜야 하니 무작정 따라갔습니다만.","JPN":"私は姉さんをお守りしなければならないので、何も考えずについて行ったのですが。","ENG":"I did follow you since I had to protect you.","TWN":"我只能跟著姊姊，因為我要保護你。"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"그때 먹었던 빙수가 참으로 맛있었습니다.","JPN":"あの時食べたかき氷がとてもおいしかったのです。","ENG":"But the shaved ice we had was delicious.","TWN":"那次刨冰，真的很好吃。"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"후후. 잠깐의 일탈이 기억에 남는다니, 치후유도 사춘기였던 걸까?","JPN":"ふふ。束の間の逸脱が記憶に残るなんて、千冬も思春期だったのかな？","ENG":"Hehe. A short deviation became such a long-lasting memory. Perhaps you were going through puberty back then.","TWN":"呵呵，短暫的叛逆也能讓你記憶深刻，千冬也是有青春期的吧？"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"흠흠. 잠깐 정도는 괜찮다고 생각합니다. 빙수를 좋아하기도 하고요.","JPN":"おほん。少しくらいは良いと思います。かき氷は好きですし。","ENG":"Ahem. Well, I think a short deviation is fine. And I do like shaved ice.","TWN":"咳咳，我想一下子應該還好，而且我也很喜歡刨冰。"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"물론, 언니와 함께 먹었다는 추억이 떠오른 게 컸습니다.","JPN":"もちろん、姉さんと一緒に食べたという思い出が思い浮かんだのが大きかったのですが。","ENG":"Of course, the main reason was because I recalled the time I had it with you.","TWN":"當然，最重要的是，和姊姊一起吃冰的回憶。"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"아, 창 밖을 보십시오. 불꽃놀이가 시작되었습니다.","JPN":"あ、窓の外を見てください。花火が始まりました。","ENG":"Oh, look out the window. The fireworks began.","TWN":"喔，快看窗外，煙火秀開始了。"},"stage":{"bg":"1THBIRTHDAY","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"BROADCAST_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>축제에 오신 모든 분께 감사 인사를 드리며.</color>","JPN":"<color=#ffd34c>お祭りにお越しくださったお客様に感謝いたします。</color>","ENG":"<color=#ffd34c>We thank you all for coming to the festival.</color>","TWN":"<color=#ffd34c>謝謝各位今天光臨。</color>"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BROADCAST_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>앞으로도 여러분들의 앞날에 축복이 가득하길 바랍니다.</color>","JPN":"<color=#ffd34c>これからも皆様の未来に祝福がありますように。</color>","ENG":"<color=#ffd34c>We wish nothing but happiness for your days ahead.</color>","TWN":"<color=#ffd34c>願每一位的未來都充滿祝福。</color>"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"아름답군요. 가문의 영지에서 보던 것과는 느낌이 다릅니다.","JPN":"綺麗ですね。家門の領地から見た花火とはまた違う感じです。","ENG":"Beautiful. It feels different from the one we saw at the estate.","TWN":"真美，和在家族領地看到的感覺完全不一樣。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"치후유 눈이 반짝거려. 혹시 언니도 그렇니?","JPN":"千冬の目がキラキラしてるわ。もしかして、私もそう？","ENG":"Your eyes are shining, Chifuyu. Are mine shining as well?","TWN":"千冬的眼睛閃閃發亮。姊姊也是嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"네. 언니도 무척이나 들떠 보이십니다.","JPN":"はい。姉さんもとても浮かれているように見えます。","ENG":"Yes. You look very happy.","TWN":"是的，姊姊的眼神看起來也非常興奮。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"후후. 그럼 잠시만……","JPN":"ふふ。それじゃあ、待ってね……","ENG":"Hehe. Then just a second...","TWN":"呵呵，你等我一下……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"짠! 치후유가 좋아하는 눈꽃 빙수야!","JPN":"じゃーん！　千冬の好きなスノーアイスよ！","ENG":"Ta da! It is the shaved ice you like!","TWN":"鏘鏘！千冬喜歡的雪花冰！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SERIOUS2"},"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"정말 시원하고 달달해 보이는 군요.","JPN":"本当に冷たくて甘そうですね。","ENG":"It looks extremely cold and sweet.","TWN":"看起來很涼很甜的感覺。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"저……언니.","JPN":"あの……姉さん。","ENG":"Um... Sis.","TWN":"那個……姊姊。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_JAPAN_CA_SENHIME_IN_TRAILER_4-3"},{"id":"L2_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"언니가 먹여주실 수…… 있나요?","JPN":"これ、食べさせてもらったらだめ……ですか？","ENG":"Could you... feed it to me?","TWN":"你……可以餵我嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_JAPAN_CA_SENHIME_IN_TRAILER_5-3"},{"id":"L3_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"아무래도 제가 직접 빙수를 먹기는 좀 힘들 것 같습니다……","JPN":"私が直接かき氷を食べることは難しいかと……","ENG":"I think it would be difficult to eat it myself...","TWN":"我好像沒辦法自己吃冰……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"제 손에 닿으면 녹아버리거든요.","JPN":"手に触れるだけで溶けてしまいますので。","ENG":"Because it melts when my hand is near.","TWN":"因為我一碰到它就會融化。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_MEMORIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"어머? 당연하지!","JPN":"あら？　もちろんよ！","ENG":"Oh? Of course I can!","TWN":"喔？當然可以！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"자, 치후유. 아~","JPN":"はい、千冬。あ～ん。","ENG":"Here, Chifuyu. Open wide!","TWN":"來，千冬，嘴巴打開～"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_MEMORIAL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"치후유가 잊지 못할 최고의 날을 만들어 주고 싶었어. 어때?","JPN":"千冬が忘れることのできない最高の日を作ってあげたかったの。どうだった？","ENG":"I wanted to make today a day you will not forget. What did you think?","TWN":"我想讓千冬度過一個難忘的日子。怎麼樣？"},"stage":{"bg":"GLOBAL1ST_01","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"잊지 못할 날이 되겠군요. 특히나 이 빙수…… 정말 달콤하고 시원합니다.","JPN":"忘れられない日になりそうです。特にこのかき氷……本当に甘くて冷たいです。","ENG":"It is truly unforgettable. Especially this shaved ice... It is so sweet and cool.","TWN":"這將是我難忘的一天。特別是這雪花冰……真的又冰又甜。"},"stage":{"bg":"GLOBAL1ST_01","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_JAPAN_CA_SENHIME_IN_TRAILER_1"},{"id":"L12_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"이렇게 행복해지니 문득 생각이 하나 떠올랐습니다.","JPN":"幸せを噛みしめていて、ふと思い浮かんだことがひとつあります。","ENG":"This overwhelming happiness reminded me of something.","TWN":"這麼幸福的時刻，讓我突然想起一件事。"},"stage":{"bg":"GLOBAL1ST_01","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_JAPAN_CA_SENHIME_IN_TRAILER_2"},{"id":"L13_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"앞으로도 언니의 곁에서 소중한 인연들을 지키고 싶군요.","JPN":"これからも姉さんのそばで、大切な人たちを守っていきたいです。","ENG":"I would like to stay by your side and protect those important to me.","TWN":"我想永遠在姊姊身邊，守護我們珍貴的緣分。"},"stage":{"bg":"GLOBAL1ST_01","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_JAPAN_CA_SENHIME_IN_TRAILER_3"},{"id":"L14_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"하지만 무작정 앞에 나서면 언니 화낼 거야?","JPN":"でも、無理やり前に出たら姉さん、怒るからね？","ENG":"But I will be angry if you act recklessly, okay?","TWN":"但要是衝動行事，姊姊會生氣的喔？"},"stage":{"bg":"GLOBAL1ST_01","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"후후. 명심하겠습니다. 아, 저기 폭죽의 색이 참 아름답군요.","JPN":"ふふ。肝に銘じます。あ、あそこ、花火の色がとても綺麗です。","ENG":"Haha. I will remember that. Oh, the fireworks over there look beautiful.","TWN":"呵呵，我會記得的。哇，那邊的煙火真美。"},"stage":{"bg":"GLOBAL1ST_01","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"이렇게 아무 걱정 없이 놀아본 건 오랜만이네.","JPN":"こうして何の心配もなく遊んだのは本当に久しぶりね。","ENG":"It has been a long while since we had fun without any concerns.","TWN":"好久沒這麼無憂無慮地玩耍。"},"stage":{"bg":"GLOBAL1ST_01","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"예. 그렇습니다. 마치 어린 시절처럼, 정말 근심 걱정 없이 놀았습니다.","JPN":"はい、本当に。まるで小さい頃のように、本当に何の心配もなく遊びました。","ENG":"Yes, it is. I fully enjoyed myself without any concerns, as if I were my younger self.","TWN":"是的。真的像小時候一樣，無憂無慮地玩。"},"stage":{"bg":"GLOBAL1ST_01","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"다음에도 종종 이렇게 놀러 올까?","JPN":"これからも時々遊びに来ようか？","ENG":"Would you like to come here again some time?","TWN":"以後也經常這樣出來玩吧？"},"stage":{"bg":"GLOBAL1ST_01","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"물론, 사나에한테만 말하고 몰래 나가는 거지.","JPN":"もちろん、早苗だけに話してこっそり出てくるのよ。","ENG":"Of course, we would only tell Sanae and sneak out.","TWN":"當然，只告訴早苗，再偷偷溜出去。"},"stage":{"bg":"GLOBAL1ST_01","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"스승님이라면 안심입니다. 잠깐의 일탈은 눈감아 주실 테니까요.","JPN":"師匠なら安心です。束の間の逸脱は見逃してくださるはずですから。","ENG":"We can trust Master. She would forgive our temporary excursions.","TWN":"師父可以放心，我們只是短暫的放鬆，她會睜一隻眼閉一隻眼的。"},"stage":{"bg":"GLOBAL1ST_01","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"가고 싶으신 곳이 있으십니까?","JPN":"行きたいところはありますか？","ENG":"Is there somewhere you would like to go?","TWN":"姊姊有想去的地方嗎？"},"stage":{"bg":"GLOBAL1ST_01","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_MEMORIAL","text":{"KOREA":"아주 많지. 치후유가 다 따라올 수 있으려나?","JPN":"たくさんあるわ。千冬に全部付いてこられるかしら？","ENG":"Many places. I wonder if you would be able to keep up.","TWN":"很多地方我都想去，千冬都要跟姊姊一起去嗎？"},"stage":{"bg":"GLOBAL1ST_01","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_MEMORIAL","text":{"KOREA":"깜짝 놀라실 겁니다. 어디를 가시든 따라갈 테니까요.","JPN":"きっと驚かれますよ。どこへ行ってもついて行きますから。","ENG":"You will be surprised, because I will follow you wherever you go.","TWN":"別嚇到喔。不管去哪裡，我都會跟姊姊一起去。"},"stage":{"bg":"GLOBAL1ST_01","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};